// === [BC44 Pipeline] LLM Route (mock + real policy) ===
const WORKFLOW_TYPE = 'llm_route';
const PIPELINE_MODE = $env.PIPELINE_MODE || 'mock';
const input = $input.first().json;
const headers = input.headers || {};
const body = input.body || {};
const expectedToken = $env.N8N_WEBHOOK_TOKEN || 'dev-local-token';
const callbackToken = $env.BASE44_CALLBACK_TOKEN || 'dev-callback-token';
const request_id  = body.request_id || headers['x-request-id'] || null;
const project_id  = body.project_id || headers['x-project-id'] || null;
const callback_url = body.callback_url || $env.BASE44_CALLBACK_URL || 'http://localhost:4000/mock-callback';
const execId = (typeof $execution !== 'undefined' && $execution.id) ? String($execution.id) : 'manual';
function envelope(status, progress, result, error) { return [{ json: { callback_url, callback_token: callbackToken, payload: { request_id, workflow_type: WORKFLOW_TYPE, project_id, status, progress, result, error, n8n_execution_id: execId } } }]; }
function fail(code, node, message, details) { return envelope('failed', 0, null, { message, node, code, details: details || {} }); }
let step = 'Validate Token';
try {
  const auth = headers['authorization'] || headers['Authorization'] || '';
  const token = String(auth).replace(/^Bearer\s+/i, '').trim();
  if (!token || token !== expectedToken) return fail('AUTH_ERROR', step, 'Invalid or missing bearer token');
  step = 'Validate Payload';
  const missing = [];
  if (!request_id) missing.push('request_id');
  if (!project_id) missing.push('project_id');
  if (!body.prompt) missing.push('prompt');
  if (missing.length) return fail('VALIDATION_ERROR', step, 'Missing required fields: ' + missing.join(', '), { missing });
  step = 'Select Provider';
  const privacy = body.privacy_level || 'normal';
  const strategy = body.routing_strategy || ((($env.DEFAULT_LLM_PROVIDER) === 'local') ? 'local_first' : 'external_primary');
  const task = body.task_type || 'generic';
  const LOCAL_MODEL = $env.LOCAL_SLLM_MODEL || 'qwen2.5:14b';
  let provider, model, policy_note = '';
  if (privacy === 'confidential' || strategy === 'privacy_strict') { provider = 'local_sllm'; model = LOCAL_MODEL; policy_note = 'confidential/privacy_strict -> local only'; }
  else if (strategy === 'local_first') { provider = 'local_sllm'; model = LOCAL_MODEL; }
  else if (strategy === 'external_primary') { provider = 'external'; model = 'gpt-4.1'; }
  else { if (task === 'evaluation' || task === 'report') { provider = 'external'; model = 'gpt-4.1'; } else { provider = 'local_sllm'; model = LOCAL_MODEL; } policy_note = 'hybrid'; }
  if (body.preferred_model) model = body.preferred_model;
  if (privacy === 'confidential' && provider === 'external') { return fail('POLICY_VIOLATION', 'Select Provider', 'confidential document cannot be sent to external LLM'); }
  if (PIPELINE_MODE === 'live') { return fail('INTERNAL_ERROR', 'Call Model', 'live mode not yet wired - set PIPELINE_MODE=mock'); }
  step = 'Call Model';
  const result = { provider: provider, model_used: model, output: '[MOCK] LLM(' + provider + ') 응답 텍스트', routing_strategy: strategy, privacy_level: privacy, fallback_used: false, latency_ms: 120, token_usage: { input_tokens: 800, output_tokens: 240 }, cost_estimate: (provider === 'external') ? 0.012 : 0.0, policy_note: policy_note, mode: 'mock' };
  return envelope('success', 100, result, null);
} catch (e) { return fail('INTERNAL_ERROR', step, (e && e.message) ? e.message : String(e)); }
